    "Mid Layer": 2,
    Layering: 2,
    Knitwear: 2,
    Shirts: 3,
    Tops: 4,
    "Inner Layer": 4,
    Bottoms: 5,
    Trousers: 5,
    Bags: 6,
    Footwear: 7,
    Jewellery: 8,
    Necklace: 8,
    Bracelet: 8,
    Ring: 8,
    Accessories: 9,
    "Small accessories": 9,
    "Small Goods": 9,
    "Objects": 9,
    Eyewear: 10,
    Sunglasses: 10,
    Glasses: 10,
    Hats: 11,
    Dress: 12,
    Dive: 12,
    Beater: 12,
    "Dress watch": 12,
    "Dive watch": 12,
    Watches: 12,
    Everyday: 12,
